#include "LibraryInventory.h"#include <iostream>#include <utility>#include <stdexcept>using namespace std;const int COMPARTMENTS_PER_SHELF = 15;Shelf &LibraryInventory::operator[](int index) {    if (index < 0 || index >= MAX_SHELF_SIZE) {        throw out_of_range("Invalid shelf index.\n");    }    return shelves[index];}void LibraryInventory::addItem(int shelf, int compartment, unique_ptr<Item> item) {    if (shelf < 0 || shelf >= MAX_SHELF_SIZE) {        throw out_of_range("Invalid shelf index.\n");    }    if (compartment < 0 || compartment >= COMPARTMENTS_PER_SHELF) {        throw out_of_range("Invalid compartment index.\n");    }    if (item == nullptr) {        cout << "Error: Cannot add a null item." << endl;        return;    }    shelves[shelf].placeItem(compartment, move(item));}void LibraryInventory::removeItem(int shelf, int compartment) {    if (shelf < 0 || shelf >= MAX_SHELF_SIZE) {        throw out_of_range("Invalid shelf index.\n");    }    if (compartment < 0 || compartment >= COMPARTMENTS_PER_SHELF) {        throw out_of_range("Invalid compartment index.\n");    }    shelves[shelf].clearCompartment(compartment);}void LibraryInventory::checkOutItem(string id, string &borrowName, string &dueDate) {    for (int shelf = 0; shelf < MAX_SHELF_SIZE; shelf++) {        for (int compartment = 0; compartment < COMPARTMENTS_PER_SHELF; compartment++) {            Item *item = shelves[shelf][compartment];            if (item != nullptr && item->getId() == id) {                if (item->isCheckedOut()) {                    cout << "Error: Item is already checked out." << endl;                    return;                }                if (borrowName.empty()) {                    cout << "Error: Borrower name cannot be empty." << endl;                    return;                }                if (dueDate.empty()) {                    cout << "Error: Due date cannot be empty." << endl;                    return;                }                item->checkOut(borrowName, dueDate);                cout << "Item checked out successfully." << endl;                cout << "ID: " << item->getId() << endl;                cout << "Borrower: " << item->getBorrowName() << endl;                cout << "Due Date: " << item->getDueDate() << endl;                return;            }        }    }    cout << "Error: Item with ID " << id << " was not found." << endl;}void LibraryInventory::checkInItem(string id) {    for (int shelf = 0; shelf < MAX_SHELF_SIZE; shelf++) {        for (int compartment = 0; compartment < COMPARTMENTS_PER_SHELF; compartment++) {            Item *item = shelves[shelf][compartment];            if (item != nullptr && item->getId() == id) {                if (!item->isCheckedOut()) {                    cout << "Error: Item is already checked in." << endl;                    return;                }                item->checkIn();                cout << "Item checked in successfully." << endl;                cout << "ID: " << item->getId() << endl;                return;            }        }    }    cout << "Error: Item with ID " << id << " was not found." << endl;}void LibraryInventory::printStoredItems() {    bool found = false;    cout << "Items currently in storage:" << endl;    for (int shelf = 0; shelf < MAX_SHELF_SIZE; shelf++) {        for (int compartment = 0; compartment < COMPARTMENTS_PER_SHELF; compartment++) {            Item *item = shelves[shelf][compartment];            if (item != nullptr && !item->isCheckedOut()) {                found = true;                cout << "Shelf: " << shelf                        << ", Compartment: " << compartment << endl;                cout << *item << endl;                cout << "------------------------" << endl;            }        }    }    if (!found) {        cout << "No items are currently checked into storage." << endl;    }}void LibraryInventory::printCheckOutItems() {    bool found = false;    cout << "Checked-out items:" << endl;    for (int shelf = 0; shelf < MAX_SHELF_SIZE; shelf++) {        for (int compartment = 0; compartment < COMPARTMENTS_PER_SHELF; compartment++) {            Item *item = shelves[shelf][compartment];            if (item != nullptr && item->isCheckedOut()) {                found = true;                cout << "Shelf: " << shelf                        << ", Compartment: " << compartment << endl;                cout << *item << endl;                cout << "Borrowed by: " << item->getBorrowName() << endl;                cout << "Due date: " << item->getDueDate() << endl;                cout << "------------------------" << endl;            }        }    }    if (!found) {        cout << "No items are currently checked out." << endl;    }}void LibraryInventory::swapItems(int shelf1, int compartment1,                                 int shelf2, int compartment2) {    if (shelf1 < 0 || shelf1 >= MAX_SHELF_SIZE ||        shelf2 < 0 || shelf2 >= MAX_SHELF_SIZE) {        throw out_of_range("Invalid shelf index.\n");    }    if (compartment1 < 0 || compartment1 >= COMPARTMENTS_PER_SHELF ||        compartment2 < 0 || compartment2 >= COMPARTMENTS_PER_SHELF) {        throw out_of_range("Invalid compartment index.\n");    }    if (shelves[shelf1].isCompartmentEmpty(compartment1) ||        shelves[shelf2].isCompartmentEmpty(compartment2)) {        cout << "Error: Cannot swap because one or both compartments are empty." << endl;        return;    }    shelves[shelf1].swapCompartments(compartment1, shelves[shelf2], compartment2);    cout << "Items swapped successfully." << endl;}